-- Таблица статей для блога
CREATE TABLE IF NOT EXISTS articles (
    id SERIAL PRIMARY KEY,
    slug VARCHAR(255) UNIQUE NOT NULL,
    title VARCHAR(500) NOT NULL,
    excerpt TEXT,
    content TEXT,
    cover_image VARCHAR(500),
    category VARCHAR(100) DEFAULT 'Советы',
    author VARCHAR(100) DEFAULT 'Редакция',
    status VARCHAR(20) DEFAULT 'PUBLISHED' CHECK (status IN ('DRAFT', 'PUBLISHED')),
    views INTEGER DEFAULT 0,
    reading_time INTEGER DEFAULT 5,
    tags VARCHAR(500),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    published_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Индексы для оптимизации
CREATE INDEX IF NOT EXISTS idx_articles_slug ON articles(slug);
CREATE INDEX IF NOT EXISTS idx_articles_status ON articles(status);
CREATE INDEX IF NOT EXISTS idx_articles_category ON articles(category);
CREATE INDEX IF NOT EXISTS idx_articles_views ON articles(views DESC);

-- Наполнение тестовыми данными (если таблица пустая)
INSERT INTO articles (slug, title, excerpt, content, category, author, status, views, reading_time, tags)
VALUES 
('kak-vybrat-luchshij-mikrozajm', 'Как выбрать лучший микрозайм', 'Узнайте, на что обратить внимание при выборе микрозайма и какие МФО предлагают лучшие условия.', '<p>Выбор микрозайма — ответственное решение, которое влияет на ваши финансы. В этой статье мы расскажем, на что обратить внимание.</p><h2>На что смотреть при выборе</h2><ul><li>Процентная ставка</li><li>Сумма займа</li><li>Срок возврата</li><li>Отзывы о МФО</li></ul><p>Мы рекомендуем сравнивать предложения и читать отзывы реальных заемщиков.</p>', 'Советы', 'Редакция', 'PUBLISHED', 15420, 5, 'микрозайм,советы,выбор'),
('pervyj-zaim-besplatno', 'Первый займ бесплатно — правда или маркетинг?', 'Большинство МФО предлагают первый займ под 0%. Разбираемся, есть ли подвох.', '<p>Многие микрофинансовые организации привлекают новых клиентов предложением первого займа под 0%.</p><h2>Условия беспроцентного займа</h2><p>Обычно условия такие:</p><ul><li>Сумма до 15 000 рублей</li><li>Срок до 30 дней</li><li>Только для новых клиентов</li></ul><p>Важно вернуть деньги в срок, иначе начисляются проценты.</p>', 'Советы', 'Редакция', 'PUBLISHED', 12350, 4, 'первый займ,бесплатно,акции'),
('chto-delat-esli-net-deneg', 'Что делать, если нечем платить займ', 'Ситуация, когда нет денег на оплату займа — неприятная, но решаемая. Узнайте о своих правах и возможностях.', '<p>Задержка с выплатой займа может случиться с каждым. Главное — не паниковать и вовремя принять меры.</p><h2>Ваши действия</h2><ol><li>Свяжитесь с МФО</li><li>Попросите отсрочку</li><li>Изучите условия реструктуризации</li></ol><p>Большинство МФО идут навстречу добросовестным заемщикам.</p>', 'Советы', 'Редакция', 'PUBLISHED', 8900, 6, 'долг,проблемы,выплата'),
('kreditnaya-istoriya-i-zaimy', 'Как микрозаймы влияют на кредитную историю', 'Разбираемся, как микрозаймы отражаются на вашей кредитной истории и могут ли они помочь получить кредит в банке.', '<p>Многие заемщики беспокоятся: не испортит ли микрозайм кредитную историю? Ответ — нет, если вы платите вовремя.</p><h2>Положительное влияние</h2><p>Своевременное погашение микрозаймов формирует положительную кредитную историю.</p>', 'Финансы', 'Редакция', 'PUBLISHED', 11200, 5, 'кредитная история,банк'),
('novye-mfo-2024', 'Новые МФО на рынке России в 2024 году', 'Обзор новых микрофинансовых организаций, которые начали работу в России в 2024 году.', '<p>Рынок микрофинансирования продолжает развиваться. Рассказываем о новых игроках.</p><h2>Тренды 2024 года</h2><ul><li>Упрощенная идентификация</li><li>Мобильные приложения</li><li>ИИ для скоринга</li></ul>', 'Новости МФО', 'Редакция', 'PUBLISHED', 7600, 4, 'новые мфо,2024')
ON CONFLICT (slug) DO NOTHING;
